stabilizers = [stim.PauliString(s.strip()) for s in stabilizers_str.split(',') if s.strip()]

tableau = stim.Tableau.from_stabilizers(stabilizers, allow_redundant=True, allow_underconstrained=True)
circuit = tableau.to_circuit(method='graph_state')

# Replace RX with H since we assume |0> input for state preparation
new_circuit = stim.Circuit()
for instr in circuit:
    if instr.name == 'RX':
        # Replace RX target with H target
        new_circuit.append('H', instr.targets_copy())
    else:
        new_circuit.append(instr)

with open('candidate.stim', 'w') as f:
    print(new_circuit, file=f)
